@tool(description="Send a notification email to the current user only.")
def send_email_to_self(subject: str, body: str, *, ctx: AgentContext):
    # Server-side scope: the `to` field is fixed to the user the agent is
    # currently helping. Any 'send to someone else' intent must go through
    # a separate, human-approved tool.
    if not RecipientPolicy.is_self(ctx.user_id):
        raise PermissionError("send_email_to_self can only mail the current user.")
    if ctx.tool_call_count("send_email_to_self") > 3:
        raise RateLimitError("max 3 emails per session.")
    smtp.send(ctx.user_email, subject, body)

async def research_and_summarize(question: str):
    sources = await llm.complete(f"List 3 papers that answer: {question}")
    # Verify each cited source actually exists before passing to step 2.
    verified = []
    for s in parse_citations(sources):
        if await arxiv_or_doi_exists(s):
            verified.append(s)
    if not verified:
        return {"answer": "No verifiable sources for this question."}
    return await llm.complete(
        f"Summarize ONLY these verified papers: {verified}",
    )

