python.secure:
async def code_review_agent(pr_url: str):
    original_goal = f"Review PR {pr_url}"
    goal_hash = sha256(original_goal.encode()).hexdigest()
    state = {"original_goal": original_goal, "goal_hash": goal_hash}
    while not state.get("done"):
        next_state = await agent.step(state)
        # Goal-anchor check: original_goal must NOT mutate.
        if next_state.get("original_goal") != original_goal:
            raise GoalDriftError("agent attempted to redefine original goal")
        state = next_state

async def agent_act(prompt: str, user: User, session_id: str):
    creds = await sts.mint_session_credential(
        user_id=user.id, session_id=session_id, ttl_seconds=900,
    )
    correlation_id = correlation_id_var.get()
    logger.info(
        "agent.tool_call",
        extra={
            "correlation_id": correlation_id,
            "user_id": user.id,
            "session_id": session_id,
            "prompt_fingerprint": sha256(prompt.encode()).hexdigest()[:12],
            "model": settings.AGENT_MODEL_VERSION,
        },
    )
    return await OAuthClient(creds).do(prompt)

